class CanaryMonitor:
    def __init__(self, max_error_rate: float = 0.05, window_seconds: int = 300):
        self.max_error_rate = max_error_rate
        self.window_seconds = window_seconds
        self._events: list[dict] = []

    def record(self, variant: str, error: bool) -> None:
        self._events.append({"variant": variant, "error": error, "ts": time.time()})
        self._prune()

    def _prune(self) -> None:
        cutoff = time.time() - self.window_seconds
        self._events = [e for e in self._events if e["ts"] > cutoff]

    def should_rollback(self) -> bool:
        canary = [e for e in self._events if e["variant"] == "canary"]
        if len(canary) < 50:
            return False   # not enough data to judge
        error_rate = sum(1 for e in canary if e["error"]) / len(canary)
        return error_rate > self.max_error_rate

    def rollback(self, router) -> None:
        router.set_canary_percentage(0)
        print(f"AUTO-ROLLBACK: canary error rate exceeded {self.max_error_rate}")

def segmented_canary_report(results: list[dict]) -> dict:
    segments = {
        "new_users":      [r for r in results if r.get("user_tenure_days", 0) < 7],
        "returning":      [r for r in results if r.get("user_tenure_days", 0) >= 7],
        "high_stakes":    [r for r in results if r.get("high_stakes")],
        "routine":        [r for r in results if not r.get("high_stakes")],
    }
    report = {}
    for seg_name, seg_results in segments.items():
        control = [r for r in seg_results if r["variant"] == "control"]
        canary  = [r for r in seg_results if r["variant"] == "canary"]
        if not control or not canary:
            continue
        ctrl_score = sum(r["score"] for r in control) / len(control)
        can_score  = sum(r["score"] for r in canary)  / len(canary)
        report[seg_name] = {
            "control_score": round(ctrl_score, 3),
            "canary_score":  round(can_score, 3),
            "delta":         round(can_score - ctrl_score, 3),
            "n_control":     len(control),
            "n_canary":      len(canary),
        }
    return report
